        uint256 available = allocation[msg.sender];
        uint256 released = withdrawn[msg.sender];

        require(available > 0, "No allocation to withdraw");
        require(block.timestamp >= releaseTime[msg.sender], "Withdrawal period not yet reached");

        withdrawn[msg.sender] = released + available;
        allocation[msg.sender] = 0;

        emit Withdrawn(msg.sender, available);
    }
}
